class Base {
  constructor(name) { this.name = name; }
  greet() { return "hello " + this.name; }
}
class Pool extends Base {
  constructor(opts) {
    super(opts.name || "pool");
    this.url = opts.url;
  }
  async query(sql) {
    return { rows: [{ sql, ok: true, name: this.name }] };
  }
}
exports.Base = Base;
exports.Pool = Pool;
